1	import type { RecipeStatus, DishStatus, MenuStatus } from "@/api/foodservice";
2	import { Badge } from "@/components/ui";
3	import { colors } from "@/styles/tokens";
4	
5	type AnyStatus = RecipeStatus | DishStatus | MenuStatus;
6	
7	const BADGE_MAP: Record<string, { bg: string; text: string; label: string }> = {
8	  DRAFT:       { bg: colors.gray100,     text: colors.gray600,    label: "Draft"       },
9	  ACTIVE:      { bg: colors.successLight, text: colors.successDark, label: "Active"      },
10	  SUPERSEDED:  { bg: colors.warningLight, text: colors.warningDark, label: "Superseded"  },
11	  ARCHIVED:    { bg: colors.dangerLight,  text: colors.dangerDark,  label: "Archived"    },
12	  PUBLISHED:   { bg: colors.infoLight,    text: colors.infoDark,    label: "Published"   },
13	  UNPUBLISHED: { bg: colors.gray200,      text: colors.gray700,     label: "Unpublished" },
14	};
15	
16	interface Props {
17	  status: AnyStatus;
18	  size?: "sm" | "md";
19	}
20	
21	export default function StatusBadge({ status, size = "sm" }: Props) {
22	  const cfg = BADGE_MAP[status] ?? { bg: colors.gray200, text: colors.gray700, label: status };
23	  return <Badge bg={cfg.bg} text={cfg.text} label={cfg.label} size={size} dot />;
24	}
