86	// Auto-unwrap paginated list responses.
87	//
88	// The backend's CursorPagination wraps list payloads as
89	// `{ count, next_cursor, previous_cursor, results: [...] }`. Most callers want
90	// a plain array, so detect that exact shape and replace `response.data` with
91	// `results`. The original wrapper is preserved on `response.pagination` so the
92	// few callers that need cursors / count (e.g. AssetsPage) can still read it.
93	// Detail/object endpoints are not affected because they don't carry both
94	// `next_cursor` and `previous_cursor` keys.
95	apiClient.interceptors.response.use((response) => {
96	  const d = response.data;
97	  if (
98	    d && typeof d === "object" && !Array.isArray(d) &&
99	    Array.isArray((d as any).results) &&
100	    "next_cursor" in d && "previous_cursor" in d
101	  ) {
102	    (response as any).pagination = d;
103	    response.data = (d as any).results;
104	  }
105	  return response;
106	});
